head.script:
// 전역 변수
scwin.memJson = $c.data.getMemInfo();
scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd");

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------

scwin.onpageload = function() {
    ica_wrkStDt.setValue(scwin.strCurDate.substring(0, 6));
    ica_wrkStDt.focus();

	const codeOptions = [
        { grpCd : "EQ010", compID : "lc_fixKndCd,gr_work_pl:fixKndCd"},
    ];

    $c.data.setCommonCode(codeOptions);

    scwin.retrieveHomeCls();
};

scwin.retrieveHomeCls = async function() {
    const params = {
        cmd: "retriveHomeClsList", 
        strVal: "",
        intVal: ""
    };

    //데이터셋에 정보설정
    dma_homeClsList.setJSON(params);

    await $c.sbm.execute(sbm_retriveHomeClsList);
}

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    let ret = await $c.gus.cfValidate([tb_wrk]);
    if (!ret) {
        return false;
    }

    await $c.sbm.execute(sbm_retrieve);
};

